import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { templateAPI } from '../services/api';
import toast from 'react-hot-toast';
import { Plus, Edit2, Trash2, Eye, X, Copy, FileText, Tag } from 'lucide-react';

const CATEGORIES = ['Promotional', 'Transactional', 'Reminder', 'Alert', 'Welcome', 'Other'];

const inp = {
  width: '100%', padding: '10px 12px', border: '1px solid #e2e8f0',
  borderRadius: '8px', fontSize: '14px', outline: 'none',
  boxSizing: 'border-box', background: 'white', color: '#0f172a',
};

// --- Highlight {{variables}} in template content ---
const HighlightedContent = ({ text }) => {
  if (!text) return null;
  const parts = text.split(/(\{\{[^}]+\}\})/g);
  return (
    <span>
      {parts.map((part, i) =>
        /^\{\{[^}]+\}\}$/.test(part) ? (
          <span key={i} style={{
            background: '#ede9fe', color: '#7c3aed',
            borderRadius: '4px', padding: '0 4px', fontSize: '13px', fontWeight: 600,
          }}>{part}</span>
        ) : (
          <span key={i}>{part}</span>
        )
      )}
    </span>
  );
};

// --- SMS counter chip ---
const SmsCounter = ({ text }) => {
  const len = text?.length || 0;
  const segments = len <= 160 ? 1 : Math.ceil(len / 153);
  const color = len > 320 ? '#dc2626' : len > 160 ? '#f59e0b' : '#16a34a';
  return (
    <span style={{
      fontSize: '12px', fontWeight: 600, color,
      background: color + '15', padding: '2px 8px', borderRadius: '20px',
    }}>
      {len} chars · {segments} SMS
    </span>
  );
};

export default function TemplatesPage() {
  const qc = useQueryClient();
  const [showModal, setShowModal]     = useState(false);
  const [editItem, setEditItem]       = useState(null);
  const [previewItem, setPreviewItem] = useState(null);
  const [search, setSearch]           = useState('');
  const [filterCat, setFilterCat]     = useState('');
  const [form, setForm] = useState({ name: '', content: '', category: '' });

  // ---------- queries ----------
  const { data: templates = [], isLoading } = useQuery({
    queryKey: ['templates', search, filterCat],
    queryFn : () => templateAPI.getAll({ search, category: filterCat }).then(r => r.data.data),
  });

  // ---------- mutations ----------
  const saveMutation = useMutation({
    mutationFn : (data) => editItem
      ? templateAPI.update(editItem.id, data)
      : templateAPI.create(data),
    onSuccess  : () => {
      qc.invalidateQueries(['templates']);
      closeModal();
      toast.success(editItem ? 'Template updated!' : 'Template created!');
    },
    onError    : (e) => toast.error(e.response?.data?.message || 'Save failed'),
  });

  const deleteMutation = useMutation({
    mutationFn : (id) => templateAPI.delete(id),
    onSuccess  : () => { qc.invalidateQueries(['templates']); toast.success('Template deleted'); },
  });

  // ---------- helpers ----------
  const openCreate = () => {
    setEditItem(null);
    setForm({ name: '', content: '', category: '' });
    setShowModal(true);
  };

  const openEdit = (t) => {
    setEditItem(t);
    setForm({ name: t.name, content: t.content, category: t.category || '' });
    setShowModal(true);
  };

  const closeModal = () => { setShowModal(false); setEditItem(null); };

  const insertVariable = (v) => {
    setForm(f => ({ ...f, content: f.content + `{{${v}}}` }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!form.name.trim() || !form.content.trim()) {
      return toast.error('Name and content are required');
    }
    saveMutation.mutate(form);
  };

  const copyContent = (text) => {
    navigator.clipboard.writeText(text);
    toast.success('Copied!');
  };

  const filtered = templates.filter(t => {
    const q = search.toLowerCase();
    if (q && !t.name.toLowerCase().includes(q) && !t.content.toLowerCase().includes(q)) return false;
    if (filterCat && t.category !== filterCat) return false;
    return true;
  });

  return (
    <div style={{ padding: '32px', background: '#f8fafc', minHeight: '100vh' }}>

      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '28px' }}>
        <div>
          <h1 style={{ fontSize: '24px', fontWeight: 700, color: '#0f172a' }}>Message Templates</h1>
          <p style={{ color: '#64748b', marginTop: '4px' }}>
            Create reusable templates with <code style={{ background: '#ede9fe', color: '#7c3aed', padding: '1px 6px', borderRadius: '4px', fontSize: '13px' }}>{'{{variable}}'}</code> personalization
          </p>
        </div>
        <button onClick={openCreate} style={{
          display: 'flex', alignItems: 'center', gap: '8px', padding: '10px 20px',
          background: 'linear-gradient(135deg, #6366f1, #8b5cf6)',
          border: 'none', borderRadius: '10px', color: 'white',
          fontWeight: 600, fontSize: '14px', cursor: 'pointer',
        }}>
          <Plus size={16} /> New Template
        </button>
      </div>

      {/* Filter bar */}
      <div style={{ display: 'flex', gap: '12px', marginBottom: '24px' }}>
        <input
          placeholder="Search templates..."
          value={search} onChange={e => setSearch(e.target.value)}
          style={{ ...inp, maxWidth: '300px', boxShadow: '0 1px 3px rgba(0,0,0,0.05)' }}
        />
        <select
          value={filterCat} onChange={e => setFilterCat(e.target.value)}
          style={{ ...inp, width: 'auto', cursor: 'pointer' }}
        >
          <option value="">All Categories</option>
          {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
        </select>
      </div>

      {/* Grid */}
      {isLoading ? (
        <div style={{ textAlign: 'center', padding: '60px', color: '#94a3b8' }}>Loading templates...</div>
      ) : filtered.length === 0 ? (
        <div style={{
          textAlign: 'center', padding: '60px',
          background: 'white', borderRadius: '16px',
          border: '2px dashed #e2e8f0',
        }}>
          <FileText size={40} style={{ color: '#cbd5e1', margin: '0 auto 16px' }} />
          <p style={{ color: '#94a3b8', fontWeight: 500 }}>No templates yet</p>
          <p style={{ color: '#cbd5e1', fontSize: '13px', marginTop: '6px' }}>Create your first template to speed up campaign creation</p>
          <button onClick={openCreate} style={{
            marginTop: '16px', padding: '9px 20px', background: '#6366f1',
            border: 'none', borderRadius: '8px', color: 'white',
            fontWeight: 500, cursor: 'pointer', fontSize: '14px',
          }}>Create Template</button>
        </div>
      ) : (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(340px, 1fr))', gap: '16px' }}>
          {filtered.map(t => (
            <div key={t.id} style={{
              background: 'white', borderRadius: '14px',
              border: '1px solid #f1f5f9', padding: '20px',
              boxShadow: '0 1px 3px rgba(0,0,0,0.04)',
              display: 'flex', flexDirection: 'column', gap: '12px',
            }}>
              {/* Card header */}
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: '15px', fontWeight: 700, color: '#0f172a' }}>{t.name}</div>
                  {t.category && (
                    <span style={{
                      display: 'inline-flex', alignItems: 'center', gap: '4px',
                      marginTop: '4px', fontSize: '11px', fontWeight: 600,
                      background: '#f0fdf4', color: '#15803d',
                      padding: '2px 8px', borderRadius: '20px',
                    }}>
                      <Tag size={10} />{t.category}
                    </span>
                  )}
                </div>
                <div style={{ display: 'flex', gap: '6px' }}>
                  <button onClick={() => setPreviewItem(t)}
                    title="Preview" style={{ padding: '6px', background: '#f8fafc', border: 'none', borderRadius: '6px', cursor: 'pointer', color: '#6366f1' }}>
                    <Eye size={14} />
                  </button>
                  <button onClick={() => copyContent(t.content)}
                    title="Copy" style={{ padding: '6px', background: '#f8fafc', border: 'none', borderRadius: '6px', cursor: 'pointer', color: '#64748b' }}>
                    <Copy size={14} />
                  </button>
                  <button onClick={() => openEdit(t)}
                    title="Edit" style={{ padding: '6px', background: '#fef3c7', border: 'none', borderRadius: '6px', cursor: 'pointer', color: '#d97706' }}>
                    <Edit2 size={14} />
                  </button>
                  <button onClick={() => { if (window.confirm('Delete template?')) deleteMutation.mutate(t.id); }}
                    title="Delete" style={{ padding: '6px', background: '#fee2e2', border: 'none', borderRadius: '6px', cursor: 'pointer', color: '#dc2626' }}>
                    <Trash2 size={14} />
                  </button>
                </div>
              </div>

              {/* Content */}
              <div style={{
                background: '#f8fafc', borderRadius: '8px', padding: '12px',
                fontSize: '13px', lineHeight: 1.6, color: '#374151',
                minHeight: '60px', maxHeight: '90px', overflowY: 'auto',
              }}>
                <HighlightedContent text={t.content} />
              </div>

              {/* Footer */}
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <SmsCounter text={t.content} />
                {t.variables?.length > 0 && (
                  <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap', justifyContent: 'flex-end' }}>
                    {t.variables.map(v => (
                      <span key={v} style={{
                        fontSize: '11px', background: '#ede9fe', color: '#7c3aed',
                        padding: '2px 6px', borderRadius: '4px', fontWeight: 500,
                      }}>{'{{' + v + '}}'}</span>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      )}

      {/* ===== CREATE / EDIT MODAL ===== */}
      {showModal && (
        <div style={{
          position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 1000,
          display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '20px',
        }}>
          <div style={{
            background: 'white', borderRadius: '20px', padding: '32px',
            width: '100%', maxWidth: '640px', maxHeight: '90vh', overflowY: 'auto',
          }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
              <h2 style={{ fontSize: '20px', fontWeight: 700, color: '#0f172a' }}>
                {editItem ? 'Edit Template' : 'Create Template'}
              </h2>
              <button onClick={closeModal} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#94a3b8' }}>
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleSubmit}>
              <div style={{ display: 'grid', gap: '16px' }}>

                {/* Name */}
                <div>
                  <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, color: '#374151', marginBottom: '6px' }}>
                    Template Name *
                  </label>
                  <input
                    style={inp} placeholder="e.g. Welcome Message"
                    value={form.name} onChange={e => setForm({ ...form, name: e.target.value })}
                    required
                  />
                </div>

                {/* Category */}
                <div>
                  <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, color: '#374151', marginBottom: '6px' }}>
                    Category
                  </label>
                  <select style={{ ...inp, cursor: 'pointer' }}
                    value={form.category} onChange={e => setForm({ ...form, category: e.target.value })}>
                    <option value="">No category</option>
                    {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>

                {/* Quick-insert variables */}
                <div>
                  <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, color: '#374151', marginBottom: '8px' }}>
                    Quick Insert Variables
                  </label>
                  <div style={{ display: 'flex', gap: '6px', flexWrap: 'wrap' }}>
                    {['first_name', 'last_name', 'full_name', 'phone', 'email'].map(v => (
                      <button
                        key={v} type="button"
                        onClick={() => insertVariable(v)}
                        style={{
                          padding: '4px 10px', borderRadius: '6px', cursor: 'pointer',
                          background: '#ede9fe', color: '#7c3aed', border: 'none',
                          fontSize: '12px', fontWeight: 600,
                        }}>
                        + {'{{'}{v}{'}}'}
                      </button>
                    ))}
                  </div>
                </div>

                {/* Content */}
                <div>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '6px' }}>
                    <label style={{ fontSize: '13px', fontWeight: 600, color: '#374151' }}>Message Content *</label>
                    <SmsCounter text={form.content} />
                  </div>
                  <textarea
                    style={{ ...inp, minHeight: '120px', resize: 'vertical', fontFamily: 'inherit', lineHeight: 1.6 }}
                    placeholder="Hi {{first_name}}, this is a message from our store..."
                    value={form.content}
                    onChange={e => setForm({ ...form, content: e.target.value })}
                    required
                  />
                  {/* Live preview with highlighted vars */}
                  {form.content && (
                    <div style={{
                      marginTop: '8px', padding: '10px 12px', background: '#f8fafc',
                      borderRadius: '8px', fontSize: '13px', color: '#374151', lineHeight: 1.6,
                      border: '1px solid #e2e8f0',
                    }}>
                      <span style={{ color: '#94a3b8', fontSize: '11px', fontWeight: 600, display: 'block', marginBottom: '4px' }}>PREVIEW</span>
                      <HighlightedContent text={form.content} />
                    </div>
                  )}
                </div>

              </div>

              <div style={{ display: 'flex', gap: '12px', marginTop: '24px', justifyContent: 'flex-end' }}>
                <button type="button" onClick={closeModal} style={{
                  padding: '10px 20px', border: '1px solid #e2e8f0',
                  borderRadius: '8px', background: 'white', cursor: 'pointer',
                  fontWeight: 500, fontSize: '14px',
                }}>Cancel</button>
                <button type="submit" disabled={saveMutation.isPending} style={{
                  padding: '10px 24px',
                  background: 'linear-gradient(135deg, #6366f1, #8b5cf6)',
                  border: 'none', borderRadius: '8px', color: 'white',
                  fontWeight: 600, fontSize: '14px', cursor: 'pointer',
                }}>
                  {saveMutation.isPending ? 'Saving...' : (editItem ? 'Update Template' : 'Create Template')}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* ===== PREVIEW MODAL ===== */}
      {previewItem && (
        <div style={{
          position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 1000,
          display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '20px',
        }}>
          <div style={{
            background: 'white', borderRadius: '20px', padding: '32px',
            width: '100%', maxWidth: '500px',
          }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
              <h3 style={{ fontSize: '18px', fontWeight: 700 }}>{previewItem.name}</h3>
              <button onClick={() => setPreviewItem(null)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#94a3b8' }}>
                <X size={20} />
              </button>
            </div>

            {/* Phone mockup */}
            <div style={{
              maxWidth: '280px', margin: '0 auto',
              background: '#f1f5f9', borderRadius: '24px', padding: '20px',
              border: '8px solid #1e293b', boxShadow: '0 20px 40px rgba(0,0,0,0.2)',
            }}>
              <div style={{ background: 'white', borderRadius: '14px', padding: '12px 14px', fontSize: '14px', lineHeight: 1.6, color: '#0f172a', boxShadow: '0 1px 4px rgba(0,0,0,0.08)' }}>
                <HighlightedContent text={previewItem.content} />
              </div>
            </div>

            <div style={{ marginTop: '20px', display: 'flex', gap: '10px', justifyContent: 'center', flexWrap: 'wrap' }}>
              <SmsCounter text={previewItem.content} />
              {previewItem.category && (
                <span style={{ fontSize: '12px', background: '#f0fdf4', color: '#15803d', padding: '2px 8px', borderRadius: '20px' }}>
                  {previewItem.category}
                </span>
              )}
            </div>

            {previewItem.variables?.length > 0 && (
              <div style={{ marginTop: '16px', padding: '12px', background: '#faf5ff', borderRadius: '10px' }}>
                <p style={{ fontSize: '12px', fontWeight: 600, color: '#7c3aed', marginBottom: '8px' }}>VARIABLES IN THIS TEMPLATE</p>
                <div style={{ display: 'flex', gap: '6px', flexWrap: 'wrap' }}>
                  {previewItem.variables.map(v => (
                    <span key={v} style={{ fontSize: '12px', background: '#ede9fe', color: '#7c3aed', padding: '3px 8px', borderRadius: '6px', fontWeight: 600 }}>
                      {'{{'}{v}{'}}'}
                    </span>
                  ))}
                </div>
              </div>
            )}

            <button onClick={() => { copyContent(previewItem.content); setPreviewItem(null); }}
              style={{
                width: '100%', marginTop: '20px', padding: '10px',
                background: '#f8fafc', border: '1px solid #e2e8f0',
                borderRadius: '8px', cursor: 'pointer', fontWeight: 500, color: '#374151',
                display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '6px',
              }}>
              <Copy size={14} /> Copy Content
            </button>
          </div>
        </div>
      )}

    </div>
  );
}
